import{_ as i,o as l,c as e,a3 as t}from"./chunks/framework.gsMzR_Kb.js";const p=JSON.parse('{"title":"象理用","description":"象理用是一条很实用的阅读路径，帮助读者从看到形式，走到理解原则，再回到现实应用。","frontmatter":{"title":"象理用","description":"象理用是一条很实用的阅读路径，帮助读者从看到形式，走到理解原则，再回到现实应用。","category":"concept","aliases":["象理用","易经象理用","xiang li yong"]},"headers":[],"relativePath":"yijing/basics/concepts/xiang-li-yong.md","filePath":"yijing/basics/concepts/xiang-li-yong.md","lastUpdated":1777132262000}'),n={name:"yijing/basics/concepts/xiang-li-yong.md"};function o(r,a,s,c,h,d){return l(),e("div",null,[...a[0]||(a[0]=[t('<h1 id="象理用" tabindex="-1">象理用 <a class="header-anchor" href="#象理用" aria-label="Permalink to &quot;象理用&quot;">​</a></h1><h2 id="定义" tabindex="-1">定义 <a class="header-anchor" href="#定义" aria-label="Permalink to &quot;定义&quot;">​</a></h2><p>“象理用”不是古书中的固定三连词条，但很适合作为今天整理阅读的方法框架：</p><ul><li>象：先看结构、形态、关系与呈现</li><li>理：再问它背后说明了什么道理</li><li>用：最后看这种道理如何落回现实判断与行动</li></ul><p>对初学者来说，这条路径比一开始就追求“讲玄理”更稳。</p><h2 id="常见误解" tabindex="-1">常见误解 <a class="header-anchor" href="#常见误解" aria-label="Permalink to &quot;常见误解&quot;">​</a></h2><ul><li>只谈象，不通向理，最后只剩符号印象</li><li>只谈理，不回到象，最后容易悬空</li><li>只谈用，不顾理路，最后容易把经典工具化</li></ul><p>较好的读法，是让三者互相牵引，而不是任意切开。</p><h2 id="在原典中的语境" tabindex="-1">在原典中的语境 <a class="header-anchor" href="#在原典中的语境" aria-label="Permalink to &quot;在原典中的语境&quot;">​</a></h2><ul><li>《周易》本身从卦象、爻象出发，这是“象”的基础。</li><li>《彖传》《象传》《系辞》则不断把象推向理。</li><li>后世读《易》若不能回到“用”，又容易把经传读成只可陈列、不可实践的知识。</li></ul><h2 id="我的理解" tabindex="-1">我的理解 <a class="header-anchor" href="#我的理解" aria-label="Permalink to &quot;我的理解&quot;">​</a></h2><p>待补：后续可把自己读某一卦时“从象到理再到用”的过程写成示例。</p><h2 id="关联页面" tabindex="-1">关联页面 <a class="header-anchor" href="#关联页面" aria-label="Permalink to &quot;关联页面&quot;">​</a></h2><ul><li><a href="/Dao/yijing/hexagrams/">六十四卦目录</a></li><li><a href="/Dao/yijing/basics/concepts/bian-yi">变易</a></li><li><a href="/Dao/yijing/basics/concepts/yin-yang">阴阳</a></li><li><a href="/Dao/topics/xiang-li-yong">专题：象理用</a></li></ul><h2 id="参考来源" tabindex="-1">参考来源 <a class="header-anchor" href="#参考来源" aria-label="Permalink to &quot;参考来源&quot;">​</a></h2><ul><li>《周易》</li><li>《象传》</li><li>《系辞上传》</li></ul>',16)])])}const g=i(n,[["render",o]]);export{p as __pageData,g as default};
